import{_ as e,o as a,c as t,O as i}from"./chunks/framework.bdcb0ee1.js";const f=JSON.parse('{"title":"Board Settings","description":"","frontmatter":{},"headers":[],"relativePath":"administration/config/settings.md","filePath":"administration/config/settings.md","lastUpdated":1773166653000}'),o={name:"administration/config/settings.md"},r=i('<h1 id="board-settings" tabindex="-1">Board Settings <a class="header-anchor" href="#board-settings" aria-label="Permalink to &quot;Board Settings&quot;">​</a></h1><p>All of the following settings can be changed from within the board settings section of the Admin CP. These are located at <code>/admin/preferences</code>. You can find them under the <strong>Board Config</strong> navigation group by clicking <strong>Settings</strong>.</p><img width="1947" height="1677" alt="image" src="https://github.com/user-attachments/assets/cc45cf6c-f308-451f-9bee-848e056da33f"><nav class="table-of-contents"><ul><li><a href="#rename-your-board">Rename your board</a></li><li><a href="#favicon">Favicon</a></li><li><a href="#toggle-board-online-status">Toggle board online status</a></li><li><a href="#disable-registrations">Disable registrations</a><ul><li><a href="#require-admin-approval">Require admin approval</a></li></ul></li><li><a href="#default-user-groups">Default user groups</a></li><li><a href="#default-avatar">Default avatar</a></li><li><a href="#active-user-cutoff">Active user cutoff</a></li><li><a href="#hot-topic-reply-count">Hot topic reply count</a></li><li><a href="#post-rate-limiting">Post rate limiting</a></li></ul></nav><h2 id="rename-your-board" tabindex="-1">Rename your board <a class="header-anchor" href="#rename-your-board" aria-label="Permalink to &quot;Rename your board&quot;">​</a></h2><p>You can control the <strong>title</strong> and <strong>description</strong> of your board here.</p><ul><li><strong>Title</strong> appears at the top of every page and in browser tabs.</li><li><strong>Description</strong> is used as a meta description for search engines.</li></ul><p>This is useful for setting your forum’s identity and improving SEO.</p><h2 id="favicon" tabindex="-1">Favicon <a class="header-anchor" href="#favicon" aria-label="Permalink to &quot;Favicon&quot;">​</a></h2><p>Upload a favicon image for your board. This is the small icon that appears in the browser tab. Common formats include <code>.ico</code> or small <code>.png</code> files.</p><h2 id="toggle-board-online-status" tabindex="-1">Toggle board online status <a class="header-anchor" href="#toggle-board-online-status" aria-label="Permalink to &quot;Toggle board online status&quot;">​</a></h2><p>Control whether your board is publicly available. If disabled:</p><ul><li>Guests cannot access the board.</li><li>Registration is blocked.</li><li>A <strong>503 - Service Unavailable</strong> response is returned.</li></ul><p>You can also define a <strong>custom offline message</strong>, which supports BBCode for formatting.</p><img width="1509" height="457" alt="image" src="https://github.com/user-attachments/assets/6aee6378-6486-454d-9756-9b9a28e3d9d9"><h2 id="disable-registrations" tabindex="-1">Disable registrations <a class="header-anchor" href="#disable-registrations" aria-label="Permalink to &quot;Disable registrations&quot;">​</a></h2><p>To make your board invite-only or prevent new signups temporarily, disable the <strong>Registrations Enabled</strong> option. When disabled, users will not be able to access the registration page.</p><h3 id="require-admin-approval" tabindex="-1">Require admin approval <a class="header-anchor" href="#require-admin-approval" aria-label="Permalink to &quot;Require admin approval&quot;">​</a></h3><p>You can require that all new user registrations be manually approved by an administrator before they gain access to the board.</p><p>When this setting is enabled:</p><ul><li>New users will not be able to log into their account until approved</li><li>Admins will receive a notification that a new user is pending</li><li>The user will receive a confirmation email once they are approved</li></ul><h2 id="default-user-groups" tabindex="-1">Default user groups <a class="header-anchor" href="#default-user-groups" aria-label="Permalink to &quot;Default user groups&quot;">​</a></h2><p>All users are assigned a user group, which determines their permissions.</p><ul><li><strong>Guest User Group</strong>: Used for unauthenticated visitors.</li><li><strong>Default User Group</strong>: Assigned to users after they register.</li></ul><p>These groups are locked from deletion while they are in use as defaults.</p><h2 id="default-avatar" tabindex="-1">Default avatar <a class="header-anchor" href="#default-avatar" aria-label="Permalink to &quot;Default avatar&quot;">​</a></h2><p>Upload an avatar image that will be used for users who haven’t set one. The image must be under 200KB and 400×400 pixels.</p><h2 id="active-user-cutoff" tabindex="-1">Active user cutoff <a class="header-anchor" href="#active-user-cutoff" aria-label="Permalink to &quot;Active user cutoff&quot;">​</a></h2><p>This setting controls how long a user is considered &quot;online&quot; after their last activity. The default is 30 minutes.</p><h2 id="hot-topic-reply-count" tabindex="-1">Hot topic reply count <a class="header-anchor" href="#hot-topic-reply-count" aria-label="Permalink to &quot;Hot topic reply count&quot;">​</a></h2><p>Define how many replies are needed before a topic is marked as &quot;hot.&quot; Set this to <code>0</code> to disable the hot topic indicator entirely.</p><h2 id="post-rate-limiting" tabindex="-1">Post rate limiting <a class="header-anchor" href="#post-rate-limiting" aria-label="Permalink to &quot;Post rate limiting&quot;">​</a></h2><p>Post rate limiting helps reduce spam and posting abuse.</p><p>You can configure:</p><ul><li><strong>Max posts</strong>: How many posts a user can make within the time window.</li><li><strong>Rate limit decay</strong>: The time window in minutes.</li></ul><p>For example, with a max of 5 posts and a decay of 1 minute, users can post 5 times per minute before being rate-limited.</p>',36),s=[r];function n(l,u,d,c,h,p){return a(),t("div",null,s)}const m=e(o,[["render",n]]);export{f as __pageData,m as default};
